            "reactions" : [ ],
            "urls" : [ ],
            "text" : "Thanks for getting back to me Bryan. We’ve reported this to our digital gurus and they’re now working on finding a fix asap. \nCould you please try these quick fixes? - they have been known to work for customers experiencing similar issues to you:\n\n1) Clear the cookies, cache, and history of your browser and try again\n2) Try using a private browser like Google Chrome Incognito\n3) Hop onto a different browser like Chrome, Microsoft Edge, or Safari\n\nIf none of these work, please let me know if you would like to make any changes to your subscription while our digital team work on fixing the issue. \n\nThanks!",
            "mediaUrls" : [ ],
            "senderId" : "106333093",
            "id" : "1399561933498486788",
            "createdAt" : "2021-06-01T03:02:22.237Z",
            "editHistory" : [ ]
