            "recipientId" : "41529681",
            "reactions" : [ ],
            "urls" : [ ],
            "text" : "Hi Bryan, we're really sorry to see you're having trouble accessing your account. So that we can flag this with our digital team can you please confirm the below details so that we can tick our privacy policy boxes.  \n\n1. Confirm the email address (or phone number) that is linked to the account/order which this concern relates to.\n2. Confirm the order number that belongs to this query.\n3. Confirm the delivery address of your most recent order.\n \nPlease also let us know if you were wanting to make changes to your subscription so we can amend that for you in the meantime.\n\nWe appreciate your patience and understanding.",
            "mediaUrls" : [ ],
            "senderId" : "106333093",
            "id" : "1399551177818349572",
            "createdAt" : "2021-06-01T02:19:37.895Z",
